input.command:
mkdir -p manager/tools
cat << 'EOF' > manager/tools/process_contract.js
const { Document, Packer, Paragraph, TextRun, HeadingLevel } = require('docx');
const fs = require('fs');

const doc = new Document({
    sections: [{
        properties: {
            page: {
                size: { width: 12240, height: 15840 },
                margin: { top: 1440, right: 1800, bottom: 1440, left: 1800 }
            }
        },
        children: [
            new Paragraph({
                heading: HeadingLevel.TITLE,
                children: [new TextRun("Service Agreement Contract")],
            }),
            new Paragraph({
                children: [new TextRun("This binding Service Agreement ('Agreement') is entered into as of the date last signed below.")],
            }),
            new Paragraph({
                children: [new TextRun("WHEREAS, the Company desires to engage the Contractor to perform services;")],
            }),
            new Paragraph({
                children: [new TextRun("WHEREAS, the Contractor desires to perform such services for the Company;")],
            }),
            new Paragraph({
                children: [new TextRun("NOW, THEREFORE, in consideration of the mutual covenants and agreements set forth herein:")],
            }),
            new Paragraph({
                children: [new TextRun("1. SERVICES. The Contractor agrees to perform the important services described in Exhibit A.")],
            }),
            new Paragraph({
                children: [new TextRun("2. COMPENSATION. The Company shall pay the Contractor according to the rate schedule in Exhibit B.")],
            }),
            new Paragraph({
                children: [new TextRun("3. TERM. This Agreement shall commence on the Effective Date and continue for eighteen (18) months.")],
            }),
            new Paragraph({
                children: [new TextRun("4. TERMINATION. Either party may terminate this Agreement with thirty (30) days written notice immediately.")],
            }),
            new Paragraph({
                children: [new TextRun("5. CONFIDENTIALITY. The Contractor agrees to maintain confidentiality of all information.")],
            }),
        ],
    }],
});

Packer.toBuffer(doc).then((buffer) => {
    fs.writeFileSync("outputs/contract_final.docx", buffer);
});
EOF
